@page "/"
@rendermode InteractiveServer
@attribute [Authorize]
@using VetClinic.Data.Models
@using VetClinic.Services
@using Microsoft.AspNetCore.Authorization
@inject ClinicService ClinicService
@inject NavigationManager Navigation

<PageTitle>VetClinic Dashboard</PageTitle>

<h1>🐾 Veterinary Clinic Dashboard</h1>

@if (loading)
{
    <p><em>Loading...</em></p>
}
else
{
    <div class="row mt-4">
        <div class="col-md-3">
            <div class="card text-bg-primary mb-3">
                <div class="card-body">
                    <h5 class="card-title">Patients</h5>
                    <p class="card-text display-6">@petCount</p>
                    <a href="pets" class="btn btn-light btn-sm">View All</a>
                </div>
            </div>
        </div>
        <div class="col-md-3">
            <div class="card text-bg-success mb-3">
                <div class="card-body">
                    <h5 class="card-title">Today's Appointments</h5>
                    <p class="card-text display-6">@todayAppointments</p>
                    <a href="appointments" class="btn btn-light btn-sm">View Schedule</a>
                </div>
            </div>
        </div>
        <div class="col-md-3">
            <div class="card text-bg-warning mb-3">
                <div class="card-body">
                    <h5 class="card-title">Pending Invoices</h5>
                    <p class="card-text display-6">@pendingInvoices</p>
                    <a href="invoices" class="btn btn-light btn-sm">View Invoices</a>
                </div>
            </div>
        </div>
        <div class="col-md-3">
            <div class="card text-bg-info mb-3">
                <div class="card-body">
                    <h5 class="card-title">Owners</h5>
                    <p class="card-text display-6">@ownerCount</p>
                    <a href="owners" class="btn btn-light btn-sm">View All</a>
                </div>
            </div>
        </div>
    </div>

    <div class="row mt-3">
        <div class="col-md-6">
            <div class="card">
                <div class="card-header d-flex justify-content-between align-items-center">
                    <strong>Today's Schedule</strong>
                    <a href="appointments/new" class="btn btn-primary btn-sm">New Appointment</a>
                </div>
                <div class="card-body">
                    @if (todayAppts.Count == 0)
                    {
                        <p class="text-muted">No appointments today.</p>
                    }
                    else
                    {
                        <table class="table table-sm">
                            <thead><tr><th>Time</th><th>Pet</th><th>Owner</th><th>Reason</th><th>Status</th></tr></thead>
                            <tbody>
                                @foreach (var a in todayAppts)
                                {
                                    <tr role="button" @onclick="() => Navigation.NavigateTo($&quot;appointments/{a.Id}&quot;)">
                                        <td>@a.StartTime.ToString("h:mm tt")</td>
                                        <td>@a.Pet.Name</td>
                                        <td>@a.Pet.Owner.FullName</td>
                                        <td>@a.Reason</td>
                                        <td>
                                            <span class="badge bg-@(a.Status == AppointmentStatus.Scheduled ? "success" : a.Status == AppointmentStatus.Completed ? "secondary" : "danger")">
                                                @a.Status
                                            </span>
                                        </td>
                                    </tr>
                                }
                            </tbody>
                        </table>
                    }
                </div>
            </div>
        </div>
        <div class="col-md-6">
            <div class="card">
                <div class="card-header d-flex justify-content-between align-items-center">
                    <strong>Recent Patients</strong>
                    <a href="pets/new" class="btn btn-primary btn-sm">Register Pet</a>
                </div>
                <div class="card-body">
                    @if (recentPets.Count == 0)
                    {
                        <p class="text-muted">No patients registered yet.</p>
                    }
                    else
                    {
                        <table class="table table-sm">
                            <thead><tr><th>Name</th><th>Species</th><th>Owner</th></tr></thead>
                            <tbody>
                                @foreach (var p in recentPets)
                                {
                                    <tr role="button" @onclick="() => Navigation.NavigateTo($&quot;pets/{p.Id}&quot;)">
                                        <td>@p.Name</td>
                                        <td>@p.Species</td>
                                        <td>@p.Owner.FullName</td>
                                    </tr>
                                }
                            </tbody>
                        </table>
                    }
                </div>
            </div>
        </div>
    </div>
}

@code {
    private bool loading = true;
    private int petCount, ownerCount, todayAppointments, pendingInvoices;
    private List<Appointment> todayAppts = [];
    private List<Pet> recentPets = [];

    protected override async Task OnInitializedAsync()
    {
        var today = DateTime.Today;
        var tomorrow = today.AddDays(1);

        var pets = await ClinicService.GetPetsAsync();
        var owners = await ClinicService.GetOwnersAsync();
        var appointments = await ClinicService.GetAppointmentsAsync(today, tomorrow);
        var invoices = await ClinicService.GetInvoicesAsync();

        petCount = pets.Count;
        ownerCount = owners.Count;
        todayAppts = appointments.Where(a => a.Status != AppointmentStatus.Cancelled).OrderBy(a => a.StartTime).ToList();
        todayAppointments = todayAppts.Count;
        pendingInvoices = invoices.Count(i => i.Status == InvoiceStatus.Pending);
        recentPets = pets.OrderByDescending(p => p.Id).Take(10).ToList();

        loading = false;
    }
}

