+    // ── Appointments ─────────────────────────────────────────
+
+    public async Task<List<Appointment>> GetAppointmentsAsync(DateTime? from, DateTime? to)
+    {
+        var query = db.Appointments
+            .Include(a => a.Pet).ThenInclude(p => p.Owner)
+            .AsQueryable();
+
+        if (from.HasValue)
+            query = query.Where(a => a.StartTime >= from.Value);
+        if (to.HasValue)
+            query = query.Where(a => a.StartTime <= to.Value);
+
+        return await query.OrderBy(a => a.StartTime).ToListAsync();
+    }
+
+    public async Task<Appointment?> GetAppointmentAsync(int id)
+        => await db.Appointments
+            .Include(a => a.Pet).ThenInclude(p => p.Owner)
+            .Include(a => a.TreatmentNotes)
+            .FirstOrDefaultAsync(a => a.Id == id);
+
+    public async Task<Appointment> SaveAppointmentAsync(Appointment appointment)
+    {
+        if (appointment.Id == 0)
+            db.Appointments.Add(appointment);
+        else
+            db.Appointments.Update(appointment);
+
+        await db.SaveChangesAsync();
+        return appointment;
+    }
+
+    public async Task CancelAppointmentAsync(int id)
+    {
+        var appointment = await db.Appointments.FindAsync(id);
+        if (appointment is not null)
+        {
+            appointment.Status = AppointmentStatus.Cancelled;
+            await db.SaveChangesAsync();
+        }
+    }
+
+    public async Task<List<Appointment>> GetAvailableSlotsAsync(DateTime date, int durationMinutes)
+    {
+        var clinicOpen = date.Date.AddHours(8);
+        var clinicClose = date.Date.AddHours(18);
+
+        var existing = await db.Appointments
+            .Where(a => a.StartTime >= clinicOpen
+                     && a.StartTime < clinicClose
+                     && a.Status != AppointmentStatus.Cancelled)
+            .OrderBy(a => a.StartTime)
+            .ToListAsync();
+
+        var slots = new List<Appointment>();
+        var slotStart = clinicOpen;
+
+        while (slotStart.AddMinutes(durationMinutes) <= clinicClose)
+        {
+            var slotEnd = slotStart.AddMinutes(durationMinutes);
+
+            var conflict = existing.Any(a =>
+                slotStart < a.StartTime.AddMinutes(a.DurationMinutes) && slotEnd > a.StartTime);
+
+            if (!conflict)
+                slots.Add(new Appointment { StartTime = slotStart, DurationMinutes = durationMinutes });
+
+            slotStart = slotStart.AddMinutes(durationMinutes);
+        }
+
+        return slots;
+    }
+
+    public async Task<bool> HasConflictAsync(DateTime startTime, int durationMinutes, int? excludeAppointmentId = null)
+    {
+        var endTime = startTime.AddMinutes(durationMinutes);
+
+        var query = db.Appointments
+            .Where(a => a.Status != AppointmentStatus.Cancelled);
+
+        if (excludeAppointmentId.HasValue)
+            query = query.Where(a => a.Id != excludeAppointmentId.Value);
+
+        return await query.AnyAsync(a =>
+            startTime < a.StartTime.AddMinutes(a.DurationMinutes) && endTime > a.StartTime);
+    }
+
+    // ── Invoices ─────────────────────────────────────────────
+
+    public async Task<List<Invoice>> GetInvoicesAsync()
+        => await db.Invoices
+            .Include(i => i.Pet).ThenInclude(p => p.Owner)
+            .Include(i => i.Items)
+            .Include(i => i.Payments)
+            .OrderByDescending(i => i.Date)
+            .ToListAsync();
+
+    public async Task<Invoice?> GetInvoiceAsync(int id)
+        => await db.Invoices
+            .Include(i => i.Pet).ThenInclude(p => p.Owner)
+            .Include(i => i.Items)
+            .Include(i => i.Payments)
+            .FirstOrDefaultAsync(i => i.Id == id);
+
+    public async Task<Invoice> SaveInvoiceAsync(Invoice invoice)
+    {
+        if (invoice.Id == 0)
+            db.Invoices.Add(invoice);
+        else
+            db.Invoices.Update(invoice);
+
+        await db.SaveChangesAsync();
+        return invoice;
+    }
+
+    public async Task<Invoice> AddInvoiceItemAsync(int invoiceId, InvoiceItem item)
+    {
+        item.InvoiceId = invoiceId;
+        db.InvoiceItems.Add(item);
+        await db.SaveChangesAsync();
+
+        return (await GetInvoiceAsync(invoiceId))!;
+    }
+
+    public async Task RemoveInvoiceItemAsync(int itemId)
+    {
+        var item = await db.InvoiceItems.FindAsync(itemId);
+        if (item is not null)
+        {
+            db.InvoiceItems.Remove(item);
+            await db.SaveChangesAsync();
+        }
+    }
+
+    // ── Payments ─────────────────────────────────────────────
+
+    public async Task<Payment> AddPaymentAsync(Payment payment)
+    {
+        db.Payments.Add(payment);
+        await db.SaveChangesAsync();
+
+        var invoice = await db.Invoices
+            .Include(i => i.Items)
+            .Include(i => i.Payments)
+            .FirstAsync(i => i.Id == payment.InvoiceId);
+
+        if (invoice.Balance <= 0)
+            invoice.Status = InvoiceStatus.Paid;
+
+        await db.SaveChangesAsync();
+        return payment;
+    }
+
+    public async Task<List<Payment>> GetPaymentHistoryAsync(int? invoiceId = null)
+    {
+        var query = db.Payments
+            .Include(p => p.Invoice)
+                .ThenInclude(i => i.Pet)
+                    .ThenInclude(pet => pet.Owner)
+            .AsQueryable();
+
+        if (invoiceId.HasValue)
+            query = query.Where(p => p.InvoiceId == invoiceId.Value);
+
+        return await query.OrderByDescending(p => p.Date).ToListAsync();
+    }
+}
