@page "/owners"
@rendermode InteractiveServer
@using VetClinic.Data.Models
@using VetClinic.Services
@using Microsoft.AspNetCore.Authorization
@attribute [Authorize]

@inject ClinicService ClinicService
@inject NavigationManager NavigationManager

<PageTitle>Pet Owners</PageTitle>

<div class="container mt-4">
    <div class="d-flex justify-content-between align-items-center mb-3">
        <h2>Pet Owners</h2>
        <button class="btn btn-primary" @onclick="ToggleAddForm">
            <i class="bi bi-plus-circle"></i> Add Owner
        </button>
    </div>

    @if (!string.IsNullOrEmpty(statusMessage))
    {
        <div class="alert @(isError ? "alert-danger" : "alert-success") alert-dismissible fade show">
            @statusMessage
            <button type="button" class="btn-close" @onclick="() => statusMessage = null"></button>
        </div>
    }

    @if (showAddForm)
    {
        <div class="card mb-4">
            <div class="card-header bg-primary text-white">New Owner</div>
            <div class="card-body">
                <EditForm Model="newOwner" OnValidSubmit="HandleAddOwner" FormName="addOwner">
                    <DataAnnotationsValidator />
                    <ValidationSummary class="text-danger" />
                    <div class="row g-3">
                        <div class="col-md-6">
                            <label class="form-label">First Name</label>
                            <InputText class="form-control" @bind-Value="newOwner.FirstName" />
                            <ValidationMessage For="() => newOwner.FirstName" />
                        </div>
                        <div class="col-md-6">
                            <label class="form-label">Last Name</label>
                            <InputText class="form-control" @bind-Value="newOwner.LastName" />
                            <ValidationMessage For="() => newOwner.LastName" />
                        </div>
                        <div class="col-md-4">
                            <label class="form-label">Phone</label>
                            <InputText class="form-control" @bind-Value="newOwner.Phone" />
                            <ValidationMessage For="() => newOwner.Phone" />
                        </div>
                        <div class="col-md-4">
                            <label class="form-label">Email</label>
                            <InputText class="form-control" @bind-Value="newOwner.Email" />
                            <ValidationMessage For="() => newOwner.Email" />
                        </div>
                        <div class="col-md-4">
                            <label class="form-label">Address</label>
                            <InputText class="form-control" @bind-Value="newOwner.Address" />
                        </div>
                    </div>
                    <div class="mt-3">
                        <button type="submit" class="btn btn-success me-2">Save</button>
                        <button type="button" class="btn btn-secondary" @onclick="ToggleAddForm">Cancel</button>
                    </div>
                </EditForm>
            </div>
        </div>
    }

    <div class="input-group mb-3" style="max-width: 400px;">
        <input type="text" class="form-control" placeholder="Search owners..."
               @bind="searchTerm" @bind:event="oninput" @bind:after="HandleSearch" />
        <span class="input-group-text"><i class="bi bi-search"></i> 🔍</span>
    </div>

    @if (owners == null)
    {
        <p><em>Loading...</em></p>
    }
    else if (!owners.Any())
    {
        <div class="alert alert-info">No owners found.</div>
    }
    else
    {
        <div class="table-responsive">
            <table class="table table-striped table-hover">
                <thead class="table-dark">
                    <tr>
                        <th>Name</th>
                        <th>Phone</th>
                        <th>Email</th>
                        <th># of Pets</th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var owner in owners)
                    {
                        <tr style="cursor: pointer;" @onclick="() => NavigateToOwner(owner.Id)">
                            <td>@owner.FullName</td>
                            <td>@owner.Phone</td>
                            <td>@owner.Email</td>
                            <td>@owner.Pets.Count</td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    }
</div>

@code {
    private List<Owner>? owners;
    private Owner newOwner = new();
    private string searchTerm = "";
    private bool showAddForm;
    private string? statusMessage;
    private bool isError;

    protected override async Task OnInitializedAsync()
    {
        owners = await ClinicService.GetOwnersAsync();
    }

    private async Task HandleSearch()
    {
        owners = string.IsNullOrWhiteSpace(searchTerm)
            ? await ClinicService.GetOwnersAsync()
            : await ClinicService.SearchOwnersAsync(searchTerm);
    }

    private void ToggleAddForm()
    {
        showAddForm = !showAddForm;
        if (showAddForm) newOwner = new Owner();
    }

    private async Task HandleAddOwner()
    {
        try
        {
            await ClinicService.SaveOwnerAsync(newOwner);
            statusMessage = "Owner added successfully.";
            isError = false;
            showAddForm = false;
            newOwner = new Owner();
            owners = await ClinicService.GetOwnersAsync();
        }
        catch (Exception ex)
        {
            statusMessage = $"Error adding owner: {ex.Message}";
            isError = true;
        }
    }

    private void NavigateToOwner(int id)
    {
        NavigationManager.NavigateTo($"/owners/{id}");
    }
}

