            </div>
            <div class="card-body">
                @if (owner.Pets == null || !owner.Pets.Any())
                {
                    <p class="text-muted">No pets registered for this owner.</p>
                }
                else
                {
                    <div class="row">
                        @foreach (var pet in owner.Pets)
                        {
                            <div class="col-md-4 mb-3">
