    private async Task HandleSave()
    {
        try
        {
            await ClinicService.SaveOwnerAsync(owner!);
            statusMessage = "Owner saved successfully.";
            isError = false;
        }
        catch (Exception ex)
        {
            statusMessage = $"Error saving owner: {ex.Message}";
            isError = true;
        }
    }

    private void ConfirmDelete()
    {
        showDeleteConfirm = true;
    }

    private async Task DeleteOwner()
    {
        try
        {
            await ClinicService.DeleteOwnerAsync(Id);
            NavigationManager.NavigateTo("/owners");
