                                        <label class="form-label">Date</label>
                                        <InputDate class="form-control" Type="InputDateType.DateTimeLocal" @bind-Value="newTreatmentNote.Date" />
                                    </div>
                                    <div class="col-md-12">
                                        <label class="form-label">Description</label>
                                        <InputTextArea class="form-control" @bind-Value="newTreatmentNote.Description" rows="3" />
                                    </div>
                                    <div class="col-md-4">
                                        <label class="form-label">Diagnosis</label>
                                        <InputText class="form-control" @bind-Value="newTreatmentNote.Diagnosis" />
                                    </div>
                                    <div class="col-md-4">
                                        <label class="form-label">Medication</label>
                                        <InputText class="form-control" @bind-Value="newTreatmentNote.Medication" />
                                    </div>
                                    <div class="col-md-4">
                                        <label class="form-label">Staff Name</label>
                                        <InputText class="form-control" @bind-Value="newTreatmentNote.StaffName" />
                                        <ValidationMessage For="() => newTreatmentNote.StaffName" />
                                    </div>
                                </div>
                                <div class="mt-3">
                                    <button type="submit" class="btn btn-success me-2">Save Note</button>
                                    <button type="button" class="btn btn-secondary" @onclick="ToggleTreatmentForm">Cancel</button>
                                </div>
                            </EditForm>
                        </div>
                    }

                    @if (pet!.TreatmentNotes == null || !pet.TreatmentNotes.Any())
                    {
                        <p class="text-muted">No treatment notes recorded.</p>
                    }
                    else
                    {
