@code {
    private List<Pet>? pets;
    private string searchTerm = "";

    protected override async Task OnInitializedAsync()
    {
        pets = await ClinicService.GetPetsAsync();
    }

    private async Task HandleSearch()
    {
        pets = string.IsNullOrWhiteSpace(searchTerm)
            ? await ClinicService.GetPetsAsync()
            : await ClinicService.SearchPetsAsync(searchTerm);
    }

    private string ComputeAge(DateOnly? dateOfBirth)
    {
        if (dateOfBirth == null) return "—";
        var today = DateOnly.FromDateTime(DateTime.Today);
        var age = today.Year - dateOfBirth.Value.Year;
        if (dateOfBirth.Value.AddYears(age) > today) age--;
        return age < 1 ? "< 1 yr" : $"{age} yr";
    }
}

