                    </div>
                    <div class="mt-3">
                        <button type="submit" class="btn btn-primary">@(IsNew ? "Register Pet" : "Save Changes")</button>
                    </div>
                </EditForm>
            </div>
        </div>

        @if (!IsNew)
        {
            <!-- Medical History -->
            <div class="card mb-4">
                <div class="card-header d-flex justify-content-between align-items-center">
                    <span>Medical History</span>
                    <button class="btn btn-sm btn-primary" @onclick="ToggleTreatmentForm">
                        @(showTreatmentForm ? "Cancel" : "Add Treatment Note")
                    </button>
                </div>
                <div class="card-body">
                    @if (showTreatmentForm)
                    {
                        <div class="border rounded p-3 mb-3 bg-light">
                            <EditForm Model="newTreatmentNote" OnValidSubmit="HandleAddTreatmentNote" FormName="addTreatment">
                                <DataAnnotationsValidator />
                                <ValidationSummary class="text-danger" />
                                <div class="row g-3">
                                    <div class="col-md-6">
                                        <label class="form-label">Title</label>
                                        <InputText class="form-control" @bind-Value="newTreatmentNote.Title" />
                                        <ValidationMessage For="() => newTreatmentNote.Title" />
                                    </div>
                                    <div class="col-md-6">
                                        <label class="form-label">Date</label>
                                        <InputDate class="form-control" Type="InputDateType.DateTimeLocal" @bind-Value="newTreatmentNote.Date" />
                                    </div>
                                    <div class="col-md-12">
                                        <label class="form-label">Description</label>
                                        <InputTextArea class="form-control" @bind-Value="newTreatmentNote.Description" rows="3" />
                                    </div>
                                    <div class="col-md-4">
                                        <label class="form-label">Diagnosis</label>
                                        <InputText class="form-control" @bind-Value="newTreatmentNote.Diagnosis" />
                                    </div>
                                    <div class="col-md-4">
                                        <label class="form-label">Medication</label>
                                        <InputText class="form-control" @bind-Value="newTreatmentNote.Medication" />
