                                    <button type="submit" class="btn btn-success me-2">Save Note</button>
                                    <button type="button" class="btn btn-secondary" @onclick="ToggleTreatmentForm">Cancel</button>
                                </div>
                            </EditForm>
                        </div>
                    }

