                            <table class="table table-sm">
                                <thead>
                                    <tr>
                                        <th>Date/Time</th>
                                        <th>Reason</th>
                                        <th>Vet</th>
                                        <th>Duration</th>
                                        <th>Status</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    @foreach (var appt in upcoming)
                                    {
                                        <tr>
                                            <td>@appt.StartTime.ToString("g")</td>
                                            <td>@appt.Reason</td>
                                            <td>@appt.VetName</td>
                                            <td>@appt.DurationMinutes min</td>
                                            <td><span class="badge bg-info">@appt.Status</span></td>
                                        </tr>
                                    }
                                </tbody>
                            </table>
                        </div>
                    }
                </div>
            </div>
        }
    }
</div>

@code {
    [Parameter] public int Id { get; set; }

    private Pet? pet;
    private List<Owner>? ownersList;
    private TreatmentNote newTreatmentNote = new();
    private bool isLoaded;
    private bool showDeleteConfirm;
    private bool showTreatmentForm;
    private string? statusMessage;
    private bool isError;
    private string currentUserName = "";

    private bool IsNew => NavigationManager.Uri.EndsWith("/pets/new", StringComparison.OrdinalIgnoreCase);

    protected override async Task OnInitializedAsync()
    {
        var authState = await AuthenticationStateProvider.GetAuthenticationStateAsync();
        currentUserName = authState.User.Identity?.Name ?? "Staff";

        ownersList = await ClinicService.GetOwnersAsync();

        if (IsNew)
        {
            pet = new Pet();
        }
        else
        {
            pet = await ClinicService.GetPetAsync(Id);
        }
        isLoaded = true;
    }

    private async Task HandleSave()
    {
        try
        {
            var saved = await ClinicService.SavePetAsync(pet!);
            statusMessage = IsNew ? "Pet registered successfully." : "Pet saved successfully.";
            isError = false;
            if (IsNew)
            {
                NavigationManager.NavigateTo($"/pets/{saved.Id}");
            }
            else
            {
                pet = await ClinicService.GetPetAsync(saved.Id);
            }
        }
        catch (Exception ex)
        {
            statusMessage = $"Error saving pet: {ex.Message}";
            isError = true;
        }
    }

    private void ConfirmDelete()
    {
        showDeleteConfirm = true;
    }

    private async Task DeletePet()
    {
        try
        {
            await ClinicService.DeletePetAsync(Id);
            NavigationManager.NavigateTo("/pets");
        }
        catch (Exception ex)
        {
            statusMessage = $"Error deleting pet: {ex.Message}";
            isError = true;
            showDeleteConfirm = false;
        }
    }

    private void ToggleTreatmentForm()
    {
        showTreatmentForm = !showTreatmentForm;
        if (showTreatmentForm)
        {
            newTreatmentNote = new TreatmentNote
            {
                PetId = Id,
                Date = DateTime.UtcNow,
                StaffName = currentUserName
            };
        }
    }

    private async Task HandleAddTreatmentNote()
    {
        try
        {
            newTreatmentNote.PetId = Id;
            await ClinicService.SaveTreatmentNoteAsync(newTreatmentNote);
            statusMessage = "Treatment note added.";
            isError = false;
            showTreatmentForm = false;
            pet = await ClinicService.GetPetAsync(Id);
        }
        catch (Exception ex)
        {
            statusMessage = $"Error saving treatment note: {ex.Message}";
            isError = true;
        }
    }

    private async Task DeleteTreatmentNote(int noteId)
    {
        try
        {
            await ClinicService.DeleteTreatmentNoteAsync(noteId);
            statusMessage = "Treatment note deleted.";
            isError = false;
            pet = await ClinicService.GetPetAsync(Id);
        }
        catch (Exception ex)
        {
            statusMessage = $"Error deleting treatment note: {ex.Message}";
            isError = true;
        }
    }
}

