using Microsoft.EntityFrameworkCore;
using VetClinic.Data;
using VetClinic.Data.Models;

namespace VetClinic.Services;

public class ClinicService(ApplicationDbContext db)
{
    public async Task<List<Invoice>> GetInvoicesAsync()
    {
        return await db.Invoices
            .Include(i => i.Pet).ThenInclude(p => p.Owner)
            .Include(i => i.Items)
            .Include(i => i.Payments)
            .OrderByDescending(i => i.Date)
            .ToListAsync();
    }

    public async Task<Invoice?> GetInvoiceAsync(int id)
    {
        return await db.Invoices
            .Include(i => i.Pet).ThenInclude(p => p.Owner)
            .Include(i => i.Items)
            .Include(i => i.Payments)
            .FirstOrDefaultAsync(i => i.Id == id);
    }

    public async Task<Invoice> SaveInvoiceAsync(Invoice invoice)
    {
        if (invoice.Id == 0)
            db.Invoices.Add(invoice);
        else
            db.Invoices.Update(invoice);

        await db.SaveChangesAsync();
        return invoice;
    }

    public async Task<Invoice> AddInvoiceItemAsync(int invoiceId, InvoiceItem item)
    {
        item.InvoiceId = invoiceId;
        db.InvoiceItems.Add(item);
        await db.SaveChangesAsync();

        return (await GetInvoiceAsync(invoiceId))!;
    }

    public async Task RemoveInvoiceItemAsync(int itemId)
    {
        var item = await db.InvoiceItems.FindAsync(itemId);
        if (item is not null)
        {
            db.InvoiceItems.Remove(item);
            await db.SaveChangesAsync();
        }
    }

    public async Task<Payment> AddPaymentAsync(Payment payment)
    {
        db.Payments.Add(payment);
        await db.SaveChangesAsync();

        var invoice = await db.Invoices
            .Include(i => i.Items)
            .Include(i => i.Payments)
            .FirstAsync(i => i.Id == payment.InvoiceId);

        if (invoice.Balance <= 0)
        {
            invoice.Status = InvoiceStatus.Paid;
            await db.SaveChangesAsync();
        }

        return payment;
    }

    public async Task<List<Payment>> GetPaymentHistoryAsync(int? invoiceId = null)
    {
        var query = db.Payments
            .Include(p => p.Invoice).ThenInclude(i => i.Pet).ThenInclude(p => p.Owner)
            .AsQueryable();

        if (invoiceId.HasValue)
            query = query.Where(p => p.InvoiceId == invoiceId.Value);

        return await query.OrderByDescending(p => p.Date).ToListAsync();
    }

    public async Task<List<Pet>> GetPetsAsync()
    {
        return await db.Pets
            .Include(p => p.Owner)
            .OrderBy(p => p.Name)
            .ToListAsync();
    }

    public async Task<List<Appointment>> GetAppointmentsAsync(DateTime? from, DateTime? to)
    {
        var query = db.Appointments
            .Include(a => a.Pet).ThenInclude(p => p.Owner)
            .AsQueryable();

        if (from.HasValue)
            query = query.Where(a => a.StartTime >= from.Value);
        if (to.HasValue)
            query = query.Where(a => a.StartTime <= to.Value);

        return await query.OrderByDescending(a => a.StartTime).ToListAsync();
    }
}

@page "/invoices"
@rendermode InteractiveServer
@attribute [Authorize]
@using VetClinic.Data.Models
@using VetClinic.Services
@using Microsoft.AspNetCore.Authorization
@inject ClinicService ClinicService
@inject NavigationManager Navigation

<PageTitle>Invoices</PageTitle>

<div class="d-flex justify-content-between align-items-center mb-3">
    <h3 class="mb-0">Invoices</h3>
    <button class="btn btn-primary" @onclick="() => Navigation.NavigateTo("/invoices/new")">
        <i class="bi bi-plus-circle"></i> Create Invoice
    </button>
</div>

@if (invoices is null)
{
    <p class="text-muted"><em>Loading...</em></p>
}
else
{
    <div class="row mb-3">
        <div class="col-md-4">
            <div class="card text-bg-warning">
                <div class="card-body py-2">
                    <small class="card-title">Total Outstanding</small>
                    <h5 class="mb-0">@FilteredInvoices.Where(i => i.Status == InvoiceStatus.Pending).Sum(i => i.Balance).ToString("C")</h5>
                </div>
            </div>
        </div>
        <div class="col-md-4">
            <div class="card text-bg-success">
                <div class="card-body py-2">
                    <small class="card-title">Total Paid</small>
                    <h5 class="mb-0">@FilteredInvoices.Sum(i => i.AmountPaid).ToString("C")</h5>
                </div>
            </div>
        </div>
    </div>

    <div class="btn-group mb-3">
        <button class="btn @(statusFilter is null ? "btn-primary" : "btn-outline-primary")" @onclick="() => SetFilter(null)">All</button>
        <button class="btn @(statusFilter == InvoiceStatus.Pending ? "btn-warning" : "btn-outline-warning")" @onclick="() => SetFilter(InvoiceStatus.Pending)">Pending</button>
        <button class="btn @(statusFilter == InvoiceStatus.Paid ? "btn-success" : "btn-outline-success")" @onclick="() => SetFilter(InvoiceStatus.Paid)">Paid</button>
        <button class="btn @(statusFilter == InvoiceStatus.Cancelled ? "btn-secondary" : "btn-outline-secondary")" @onclick="() => SetFilter(InvoiceStatus.Cancelled)">Cancelled</button>
    </div>

    @if (!FilteredInvoices.Any())
    {
        <div class="alert alert-info">No invoices found.</div>
    }
    else
    {
        <div class="table-responsive">
            <table class="table table-hover align-middle">
                <thead class="table-light">
                    <tr>
                        <th>Invoice #</th>
                        <th>Date</th>
                        <th>Pet</th>
                        <th>Owner</th>
                        <th class="text-end">Total</th>
                        <th class="text-end">Paid</th>
                        <th class="text-end">Balance</th>
                        <th>Status</th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var inv in FilteredInvoices)
                    {
                        <tr role="button" @onclick="() => Navigation.NavigateTo($"/invoices/{inv.Id}")">
                            <td>@inv.Id</td>
                            <td>@inv.Date.ToShortDateString()</td>
                            <td>@inv.Pet.Name</td>
                            <td>@inv.Pet.Owner.FullName</td>
                            <td class="text-end">@inv.Total.ToString("C")</td>
                            <td class="text-end">@inv.AmountPaid.ToString("C")</td>
                            <td class="text-end">@inv.Balance.ToString("C")</td>
                            <td><span class="badge @StatusBadgeClass(inv.Status)">@inv.Status</span></td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    }
}

@code {
    private List<Invoice>? invoices;
    private InvoiceStatus? statusFilter;

    private IEnumerable<Invoice> FilteredInvoices =>
        statusFilter.HasValue ? invoices!.Where(i => i.Status == statusFilter.Value) : invoices!;

    protected override async Task OnInitializedAsync()
    {
        invoices = await ClinicService.GetInvoicesAsync();
    }

    private void SetFilter(InvoiceStatus? status) => statusFilter = status;

    private static string StatusBadgeClass(InvoiceStatus status) => status switch
    {
        InvoiceStatus.Pending => "bg-warning text-dark",
        InvoiceStatus.Paid => "bg-success",
        InvoiceStatus.Cancelled => "bg-secondary",
        _ => "bg-secondary"
    };
}

@page "/invoices/{Id:int}"
@page "/invoices/new"
@rendermode InteractiveServer
@attribute [Authorize]
@using VetClinic.Data.Models
@using VetClinic.Services
@using Microsoft.AspNetCore.Authorization
@inject ClinicService ClinicService
@inject NavigationManager Navigation

<PageTitle>@(IsNew ? "New Invoice" : $"Invoice #{Id}")</PageTitle>

@if (loading)
{
    <p class="text-muted"><em>Loading...</em></p>
}
else if (!IsNew && invoice is null)
{
    <div class="alert alert-danger">Invoice not found.</div>
}
else if (IsNew)
{
    @* ── New invoice form ── *@
    <h3>Create Invoice</h3>

    @if (errorMessage is not null)
    {
        <div class="alert alert-danger alert-dismissible fade show">
            @errorMessage
            <button type="button" class="btn-close" @onclick="() => errorMessage = null"></button>
        </div>
    }

    <EditForm Model="newInvoice" OnValidSubmit="CreateInvoice" FormName="newInvoiceForm">
        <DataAnnotationsValidator />

        <div class="mb-3">
            <label class="form-label">Pet</label>
            <select class="form-select" @bind="newInvoice.PetId">
                <option value="0">-- Select a pet --</option>
                @foreach (var p in pets)
                {
                    <option value="@p.Id">@p.Name - @p.Owner.FullName</option>
                }
            </select>
        </div>

        <div class="mb-3">
            <label class="form-label">Appointment (optional)</label>
            <select class="form-select" @bind="newInvoice.AppointmentId">
                <option value="">-- None --</option>
                @foreach (var a in petAppointments)
                {
                    <option value="@a.Id">@a.StartTime.ToShortDateString() – @a.Reason</option>
                }
            </select>
        </div>

        <div class="mb-3">
            <label class="form-label">Date</label>
            <InputDate class="form-control" @bind-Value="newInvoice.Date" />
        </div>

        <div class="mb-3">
            <label class="form-label">Notes</label>
            <InputTextArea class="form-control" @bind-Value="newInvoice.Notes" rows="3" />
        </div>

        <button type="submit" class="btn btn-primary" disabled="@saving">
            @(saving ? "Saving..." : "Create Invoice")
        </button>
        <button type="button" class="btn btn-outline-secondary ms-2" @onclick="() => Navigation.NavigateTo("/invoices")">Cancel</button>
    </EditForm>
}
else
{
    @* ── Existing invoice view/edit ── *@
    <div class="d-flex justify-content-between align-items-center mb-3">
        <div>
            <h3 class="mb-0">
                Invoice #@invoice!.Id
                <span class="badge @StatusBadgeClass(invoice.Status) ms-2">@invoice.Status</span>
            </h3>
            <small class="text-muted">
                @invoice.Date.ToShortDateString() &middot; @invoice.Pet.Name &middot; @invoice.Pet.Owner.FullName
            </small>
        </div>
        <button class="btn btn-outline-secondary btn-sm" @onclick="() => Navigation.NavigateTo("/invoices")">
            &larr; Back to Invoices
        </button>
    </div>

    @if (successMessage is not null)
    {
        <div class="alert alert-success alert-dismissible fade show">
            @successMessage
            <button type="button" class="btn-close" @onclick="() => successMessage = null"></button>
        </div>
    }
    @if (errorMessage is not null)
    {
        <div class="alert alert-danger alert-dismissible fade show">
            @errorMessage
            <button type="button" class="btn-close" @onclick="() => errorMessage = null"></button>
        </div>
    }

    @* Notes & Status *@
    <div class="card mb-4">
        <div class="card-body">
            <div class="row g-3">
                <div class="col-md-8">
                    <label class="form-label fw-bold">Notes</label>
                    <textarea class="form-control" rows="2" @bind="invoice.Notes"></textarea>
                </div>
                <div class="col-md-4 d-flex align-items-end gap-2">
                    <button class="btn btn-primary" @onclick="SaveNotes" disabled="@saving">Save Notes</button>
                    @if (invoice.Status == InvoiceStatus.Pending)
                    {
                        <button class="btn btn-outline-danger" @onclick="CancelInvoice" disabled="@saving">Cancel Invoice</button>
                    }
                </div>
            </div>
        </div>
    </div>

    @* ── Line Items ── *@
    <div class="card mb-4">
        <div class="card-header fw-bold">Line Items</div>
        <div class="card-body p-0">
            <table class="table table-sm mb-0">
                <thead class="table-light">
                    <tr>
                        <th>Description</th>
                        <th class="text-end" style="width:150px">Amount</th>
                        <th style="width:60px"></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var item in invoice.Items)
                    {
                        <tr>
                            <td>@item.Description</td>
                            <td class="text-end">@item.Amount.ToString("C")</td>
                            <td class="text-center">
                                <button class="btn btn-sm btn-outline-danger" title="Remove" @onclick="() => RemoveItem(item.Id)">✕</button>
                            </td>
                        </tr>
                    }
                    @if (!invoice.Items.Any())
                    {
                        <tr><td colspan="3" class="text-muted text-center">No items yet.</td></tr>
                    }
                </tbody>
                <tfoot>
                    <tr class="table-light">
                        <td>
                            <input class="form-control form-control-sm" placeholder="Description" @bind="newItem.Description" />
                        </td>
                        <td>
                            <input type="number" step="0.01" min="0" class="form-control form-control-sm text-end" placeholder="0.00" @bind="newItem.Amount" />
                        </td>
                        <td class="text-center">
                            <button class="btn btn-sm btn-success" @onclick="AddItem" disabled="@saving">+</button>
                        </td>
                    </tr>
                    <tr>
                        <td class="text-end fw-bold">Total</td>
                        <td class="text-end fw-bold">@invoice.Total.ToString("C")</td>
                        <td></td>
                    </tr>
                </tfoot>
            </table>
        </div>
    </div>

    @* ── Payments ── *@
    <div class="card mb-4">
        <div class="card-header fw-bold">Payments</div>
        <div class="card-body p-0">
