            </div>
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private bool IsNew => Id == 0;
    private bool loading = true;
    private bool saving;
    private string? successMessage;
    private string? errorMessage;

    private Invoice? invoice;
    private Invoice newInvoice = new() { Date = DateTime.UtcNow };
    private InvoiceItem newItem = new();
    private Payment newPayment = new() { Date = DateTime.UtcNow };

    private List<Pet> pets = [];
    private List<Appointment> petAppointments = [];

    protected override async Task OnInitializedAsync()
    {
        if (IsNew)
        {
            pets = await ClinicService.GetPetsAsync();
        }
        else
        {
            invoice = await ClinicService.GetInvoiceAsync(Id);
        }
        loading = false;
    }

    // Refresh appointments when pet selection changes
    private async Task OnPetChanged(ChangeEventArgs e)
    {
        if (int.TryParse(e.Value?.ToString(), out var petId) && petId > 0)
        {
            newInvoice.PetId = petId;
            var from = DateTime.UtcNow.AddMonths(-3);
            var all = await ClinicService.GetAppointmentsAsync(from, DateTime.UtcNow);
            petAppointments = all.Where(a => a.PetId == petId).ToList();
        }
        else
        {
            petAppointments = [];
        }
        newInvoice.AppointmentId = null;
    }

    private async Task CreateInvoice()
    {
        if (newInvoice.PetId == 0)
        {
            errorMessage = "Please select a pet.";
            return;
        }

        saving = true;
        errorMessage = null;
        try
        {
            var created = await ClinicService.SaveInvoiceAsync(newInvoice);
            Navigation.NavigateTo($"/invoices/{created.Id}");
        }
        catch (Exception ex)
        {
            errorMessage = $"Error creating invoice: {ex.Message}";
        }
        finally
        {
            saving = false;
        }
    }

    private async Task SaveNotes()
    {
        saving = true;
        errorMessage = null;
        try
        {
            await ClinicService.SaveInvoiceAsync(invoice!);
            successMessage = "Notes saved.";
        }
        catch (Exception ex)
        {
            errorMessage = $"Error saving: {ex.Message}";
        }
        finally
        {
            saving = false;
        }
    }

    private async Task CancelInvoice()
    {
        saving = true;
        errorMessage = null;
        try
        {
            invoice!.Status = InvoiceStatus.Cancelled;
            await ClinicService.SaveInvoiceAsync(invoice);
            successMessage = "Invoice cancelled.";
        }
        catch (Exception ex)
        {
            errorMessage = $"Error cancelling: {ex.Message}";
        }
        finally
        {
            saving = false;
        }
    }

    private async Task AddItem()
    {
        if (string.IsNullOrWhiteSpace(newItem.Description) || newItem.Amount <= 0)
        {
            errorMessage = "Please enter a description and a positive amount.";
            return;
        }

        saving = true;
        errorMessage = null;
        try
        {
            invoice = await ClinicService.AddInvoiceItemAsync(invoice!.Id, newItem);
            newItem = new();
            successMessage = "Item added.";
        }
        catch (Exception ex)
        {
            errorMessage = $"Error adding item: {ex.Message}";
        }
        finally
        {
            saving = false;
        }
    }

    private async Task RemoveItem(int itemId)
    {
        saving = true;
        errorMessage = null;
        try
        {
            await ClinicService.RemoveInvoiceItemAsync(itemId);
            invoice = await ClinicService.GetInvoiceAsync(invoice!.Id);
            successMessage = "Item removed.";
        }
        catch (Exception ex)
        {
            errorMessage = $"Error removing item: {ex.Message}";
        }
        finally
        {
            saving = false;
        }
    }

    private async Task RecordPayment()
    {
        if (newPayment.Amount <= 0)
        {
            errorMessage = "Payment amount must be positive.";
            return;
        }

        saving = true;
        errorMessage = null;
        try
        {
            newPayment.InvoiceId = invoice!.Id;
            await ClinicService.AddPaymentAsync(newPayment);
            invoice = await ClinicService.GetInvoiceAsync(invoice.Id);
            newPayment = new() { Date = DateTime.UtcNow, Amount = invoice!.Balance > 0 ? invoice.Balance : 0 };
            successMessage = "Payment recorded.";
        }
        catch (Exception ex)
        {
            errorMessage = $"Error recording payment: {ex.Message}";
        }
        finally
        {
            saving = false;
        }
    }

    private static string StatusBadgeClass(InvoiceStatus status) => status switch
    {
        InvoiceStatus.Pending => "bg-warning text-dark",
        InvoiceStatus.Paid => "bg-success",
        InvoiceStatus.Cancelled => "bg-secondary",
        _ => "bg-secondary"
    };
}

