                result = result.Where(p => p.Date.Date >= dateFrom.Value.Date);
            if (dateTo.HasValue)
                result = result.Where(p => p.Date.Date <= dateTo.Value.Date);
            return result;
        }
    }

    protected override async Task OnInitializedAsync()
    {
        payments = await ClinicService.GetPaymentHistoryAsync();
    }

    private void ApplyFilter() { /* FilteredPayments recomputes automatically */ }

    private void ClearFilter()
    {
        dateFrom = null;
        dateTo = null;
    }
}

using Microsoft.EntityFrameworkCore;
using VetClinic.Data;
using VetClinic.Data.Models;

namespace VetClinic.Services;

public class ClinicService(ApplicationDbContext db)
{
    public async Task<List<Invoice>> GetInvoicesAsync()
    {
        return await db.Invoices
            .Include(i => i.Pet).ThenInclude(p => p.Owner)
            .Include(i => i.Items)
            .Include(i => i.Payments)
            .OrderByDescending(i => i.Date)
            .ToListAsync();
    }

    public async Task<Invoice?> GetInvoiceAsync(int id)
    {
        return await db.Invoices
            .Include(i => i.Pet).ThenInclude(p => p.Owner)
            .Include(i => i.Items)
            .Include(i => i.Payments)
            .FirstOrDefaultAsync(i => i.Id == id);
    }

    public async Task<Invoice> SaveInvoiceAsync(Invoice invoice)
    {
        if (invoice.Id == 0)
            db.Invoices.Add(invoice);
        else
            db.Invoices.Update(invoice);

        await db.SaveChangesAsync();
        return invoice;
    }

    public async Task<Invoice> AddInvoiceItemAsync(int invoiceId, InvoiceItem item)
    {
        item.InvoiceId = invoiceId;
        db.InvoiceItems.Add(item);
        await db.SaveChangesAsync();

        return (await GetInvoiceAsync(invoiceId))!;
    }

    public async Task RemoveInvoiceItemAsync(int itemId)
    {
        var item = await db.InvoiceItems.FindAsync(itemId);
        if (item is not null)
        {
            db.InvoiceItems.Remove(item);
            await db.SaveChangesAsync();
        }
    }

    public async Task<Payment> AddPaymentAsync(Payment payment)
    {
        db.Payments.Add(payment);
        await db.SaveChangesAsync();

        var invoice = await db.Invoices
            .Include(i => i.Items)
            .Include(i => i.Payments)
            .FirstAsync(i => i.Id == payment.InvoiceId);

        if (invoice.Balance <= 0)
        {
            invoice.Status = InvoiceStatus.Paid;
            await db.SaveChangesAsync();
        }

        return payment;
    }

    public async Task<List<Payment>> GetPaymentHistoryAsync(int? invoiceId = null)
    {
        var query = db.Payments
            .Include(p => p.Invoice).ThenInclude(i => i.Pet).ThenInclude(p => p.Owner)
            .AsQueryable();

        if (invoiceId.HasValue)
            query = query.Where(p => p.InvoiceId == invoiceId.Value);

        return await query.OrderByDescending(p => p.Date).ToListAsync();
    }

    public async Task<List<Pet>> GetPetsAsync()
    {
        return await db.Pets
            .Include(p => p.Owner)
            .OrderBy(p => p.Name)
            .ToListAsync();
    }

    public async Task<List<Appointment>> GetAppointmentsAsync(DateTime? from, DateTime? to)
    {
        var query = db.Appointments
            .Include(a => a.Pet).ThenInclude(p => p.Owner)
            .AsQueryable();

        if (from.HasValue)
            query = query.Where(a => a.StartTime >= from.Value);
        if (to.HasValue)
            query = query.Where(a => a.StartTime <= to.Value);

        return await query.OrderByDescending(a => a.StartTime).ToListAsync();
    }
}

