@code {
    [Parameter] public int Id { get; set; }

    private bool IsNew => Id == 0;
    private bool loading = true;
    private bool saving;
    private string? successMessage;
    private string? errorMessage;

    private Invoice? invoice;
    private Invoice newInvoice = new() { Date = DateTime.UtcNow };
    private InvoiceItem newItem = new();
    private Payment newPayment = new() { Date = DateTime.UtcNow };

    private List<Pet> pets = [];
    private List<Appointment> petAppointments = [];

    protected override async Task OnInitializedAsync()
    {
        if (IsNew)
        {
            pets = await ClinicService.GetPetsAsync();
        }
        else
        {
            invoice = await ClinicService.GetInvoiceAsync(Id);
        }
        loading = false;
    }

    // Refresh appointments when pet selection changes
    private async Task OnPetChanged(ChangeEventArgs e)
    {
        if (int.TryParse(e.Value?.ToString(), out var petId) && petId > 0)
        {
            newInvoice.PetId = petId;
            var from = DateTime.UtcNow.AddMonths(-3);
            var all = await ClinicService.GetAppointmentsAsync(from, DateTime.UtcNow);
            petAppointments = all.Where(a => a.PetId == petId).ToList();
        }
        else
        {
            petAppointments = [];
        }
        newInvoice.AppointmentId = null;
    }

    private async Task CreateInvoice()
    {
        if (newInvoice.PetId == 0)
        {
            errorMessage = "Please select a pet.";
            return;
        }

        saving = true;
        errorMessage = null;
        try
        {
            var created = await ClinicService.SaveInvoiceAsync(newInvoice);
            Navigation.NavigateTo($"/invoices/{created.Id}");
        }
        catch (Exception ex)
        {
            errorMessage = $"Error creating invoice: {ex.Message}";
        }
        finally
        {
            saving = false;
        }
    }

    private async Task SaveNotes()
    {
        saving = true;
        errorMessage = null;
        try
        {
            await ClinicService.SaveInvoiceAsync(invoice!);
            successMessage = "Notes saved.";
        }
        catch (Exception ex)
        {
            errorMessage = $"Error saving: {ex.Message}";
        }
        finally
        {
            saving = false;
        }
    }

    private async Task CancelInvoice()
    {
        saving = true;
        errorMessage = null;
        try
        {
            invoice!.Status = InvoiceStatus.Cancelled;
            await ClinicService.SaveInvoiceAsync(invoice);
            successMessage = "Invoice cancelled.";
        }
        catch (Exception ex)
        {
            errorMessage = $"Error cancelling: {ex.Message}";
        }
        finally
        {
            saving = false;
        }
    }

    private async Task AddItem()
    {
        if (string.IsNullOrWhiteSpace(newItem.Description) || newItem.Amount <= 0)
        {
            errorMessage = "Please enter a description and a positive amount.";
            return;
        }

        saving = true;
        errorMessage = null;
        try
        {
            invoice = await ClinicService.AddInvoiceItemAsync(invoice!.Id, newItem);
            newItem = new();
            successMessage = "Item added.";
        }
        catch (Exception ex)
        {
            errorMessage = $"Error adding item: {ex.Message}";
        }
        finally
        {
            saving = false;
        }
    }

    private async Task RemoveItem(int itemId)
    {
        saving = true;
        errorMessage = null;
        try
        {
            await ClinicService.RemoveInvoiceItemAsync(itemId);
            invoice = await ClinicService.GetInvoiceAsync(invoice!.Id);
            successMessage = "Item removed.";
        }
        catch (Exception ex)
        {
            errorMessage = $"Error removing item: {ex.Message}";
        }
        finally
        {
            saving = false;
        }
    }

    private async Task RecordPayment()
    {
        if (newPayment.Amount <= 0)
        {
            errorMessage = "Payment amount must be positive.";
            return;
        }

        saving = true;
        errorMessage = null;
        try
        {
            newPayment.InvoiceId = invoice!.Id;
            await ClinicService.AddPaymentAsync(newPayment);
            invoice = await ClinicService.GetInvoiceAsync(invoice.Id);
            newPayment = new() { Date = DateTime.UtcNow, Amount = invoice!.Balance > 0 ? invoice.Balance : 0 };
            successMessage = "Payment recorded.";
        }
        catch (Exception ex)
        {
            errorMessage = $"Error recording payment: {ex.Message}";
        }
        finally
        {
            saving = false;
        }
    }

    private static string StatusBadgeClass(InvoiceStatus status) => status switch
    {
        InvoiceStatus.Pending => "bg-warning text-dark",
        InvoiceStatus.Paid => "bg-success",
        InvoiceStatus.Cancelled => "bg-secondary",
        _ => "bg-secondary"
    };
}

@page "/payments"
@rendermode InteractiveServer
@attribute [Authorize]
@using VetClinic.Data.Models
@using VetClinic.Services
@using Microsoft.AspNetCore.Authorization
@inject ClinicService ClinicService
@inject NavigationManager Navigation

<PageTitle>Payment History</PageTitle>

<h3 class="mb-3">Payment History</h3>

<div class="row g-2 mb-3 align-items-end">
    <div class="col-auto">
        <label class="form-label">From</label>
        <input type="date" class="form-control form-control-sm" @bind="dateFrom" @bind:event="onchange" @bind:after="ApplyFilter" />
    </div>
    <div class="col-auto">
        <label class="form-label">To</label>
        <input type="date" class="form-control form-control-sm" @bind="dateTo" @bind:event="onchange" @bind:after="ApplyFilter" />
    </div>
    <div class="col-auto">
        <button class="btn btn-sm btn-outline-secondary" @onclick="ClearFilter">Clear</button>
    </div>
</div>

@if (payments is null)
{
    <p class="text-muted"><em>Loading...</em></p>
}
else
{
    <div class="card mb-3">
        <div class="card-body py-2">
            <strong>Total:</strong> @FilteredPayments.Sum(p => p.Amount).ToString("C")
            <span class="text-muted ms-3">(@FilteredPayments.Count() payment(s))</span>
        </div>
    </div>

    @if (!FilteredPayments.Any())
    {
        <div class="alert alert-info">No payments found.</div>
    }
    else
    {
        <div class="table-responsive">
            <table class="table table-hover align-middle">
                <thead class="table-light">
                    <tr>
                        <th>Date</th>
                        <th>Invoice #</th>
                        <th>Pet</th>
                        <th>Owner</th>
                        <th class="text-end">Amount</th>
                        <th>Method</th>
                        <th>Reference</th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var pmt in FilteredPayments)
                    {
                        <tr>
                            <td>@pmt.Date.ToShortDateString()</td>
                            <td>
                                <a href="/invoices/@pmt.InvoiceId">@pmt.InvoiceId</a>
                            </td>
                            <td>@pmt.Invoice.Pet.Name</td>
                            <td>@pmt.Invoice.Pet.Owner.FullName</td>
                            <td class="text-end">@pmt.Amount.ToString("C")</td>
                            <td>@pmt.Method</td>
                            <td>@pmt.Reference</td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    }
}

@code {
    private List<Payment>? payments;
    private DateTime? dateFrom;
    private DateTime? dateTo;

    private IEnumerable<Payment> FilteredPayments
    {
        get
        {
            IEnumerable<Payment> result = payments!;
            if (dateFrom.HasValue)
                result = result.Where(p => p.Date.Date >= dateFrom.Value.Date);
            if (dateTo.HasValue)
                result = result.Where(p => p.Date.Date <= dateTo.Value.Date);
            return result;
        }
    }

    protected override async Task OnInitializedAsync()
    {
        payments = await ClinicService.GetPaymentHistoryAsync();
    }

    private void ApplyFilter() { /* FilteredPayments recomputes automatically */ }

    private void ClearFilter()
    {
        dateFrom = null;
        dateTo = null;
    }
}

