1. using Microsoft.EntityFrameworkCore;
2. using VetClinic.Data;
3. using VetClinic.Data.Models;
4. 
5. namespace VetClinic.Services;
6. 
7. public class ClinicService(ApplicationDbContext db)
8. {
9.     // ── Owners ───────────────────────────────────────────────
10. 
11.     public async Task<List<Owner>> GetOwnersAsync()
12.         => await db.Owners.Include(o => o.Pets).OrderBy(o => o.LastName).ToListAsync();
13. 
14.     public async Task<Owner?> GetOwnerAsync(int id)
15.         => await db.Owners.Include(o => o.Pets).FirstOrDefaultAsync(o => o.Id == id);
16. 
17.     public async Task<Owner> SaveOwnerAsync(Owner owner)
18.     {
19.         if (owner.Id == 0)
20.             db.Owners.Add(owner);
21.         else
22.             db.Owners.Update(owner);
23. 
24.         await db.SaveChangesAsync();
25.         return owner;
26.     }
27. 
28.     public async Task DeleteOwnerAsync(int id)
29.     {
30.         var owner = await db.Owners.FindAsync(id);
31.         if (owner is not null)
32.         {
33.             db.Owners.Remove(owner);
34.             await db.SaveChangesAsync();
35.         }
36.     }
37. 
38.     public async Task<List<Owner>> SearchOwnersAsync(string term)
39.     {
40.         var lower = term.ToLower();
41.         return await db.Owners
42.             .Include(o => o.Pets)
43.             .Where(o => o.FirstName.ToLower().Contains(lower)
44.                      || o.LastName.ToLower().Contains(lower)
45.                      || o.Phone.Contains(term))
46.             .OrderBy(o => o.LastName)
47.             .ToListAsync();
48.     }
49. 
50.     // ── Pets ─────────────────────────────────────────────────
51. 
52.     public async Task<List<Pet>> GetPetsAsync()
53.         => await db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
54. 
55.     public async Task<Pet?> GetPetAsync(int id)
56.         => await db.Pets
57.             .Include(p => p.Owner)
58.             .Include(p => p.TreatmentNotes)
59.             .Include(p => p.Appointments)
60.             .FirstOrDefaultAsync(p => p.Id == id);
61. 
62.     public async Task<Pet> SavePetAsync(Pet pet)
63.     {
64.         if (pet.Id == 0)
65.             db.Pets.Add(pet);
66.         else
67.             db.Pets.Update(pet);
68. 
69.         await db.SaveChangesAsync();
70.         return pet;
71.     }
72. 
73.     public async Task DeletePetAsync(int id)
74.     {
75.         var pet = await db.Pets.FindAsync(id);
76.         if (pet is not null)
77.         {
78.             db.Pets.Remove(pet);
79.             await db.SaveChangesAsync();
80.         }
81.     }
82. 
83.     public async Task<List<Pet>> SearchPetsAsync(string term)
84.     {
85.         var lower = term.ToLower();
86.         return await db.Pets
87.             .Include(p => p.Owner)
88.             .Where(p => p.Name.ToLower().Contains(lower)
89.                      || p.Species.ToLower().Contains(lower)
90.                      || p.Owner.FirstName.ToLower().Contains(lower)
91.                      || p.Owner.LastName.ToLower().Contains(lower))
92.             .OrderBy(p => p.Name)
93.             .ToListAsync();
94.     }
95. 
96.     // ── Treatment Notes ──────────────────────────────────────
97. 
98.     public async Task<TreatmentNote> SaveTreatmentNoteAsync(TreatmentNote note)
99.     {
100.         if (note.Id == 0)
101.             db.TreatmentNotes.Add(note);
102.         else
103.             db.TreatmentNotes.Update(note);
104. 
105.         await db.SaveChangesAsync();
106.         return note;
107.     }
108. 
109.     public async Task DeleteTreatmentNoteAsync(int id)
110.     {
111.         var note = await db.TreatmentNotes.FindAsync(id);
112.         if (note is not null)
113.         {
114.             db.TreatmentNotes.Remove(note);
115.             await db.SaveChangesAsync();
116.         }
