@page "/appointments"
@rendermode InteractiveServer
@attribute [Authorize]
@using VetClinic.Data.Models
@using VetClinic.Services
@using Microsoft.AspNetCore.Authorization
@inject ClinicService ClinicService
@inject NavigationManager Navigation

<PageTitle>Appointment Schedule</PageTitle>

<div class="d-flex justify-content-between align-items-center mb-3">
    <h2 class="mb-0">Appointment Schedule</h2>
    <button class="btn btn-primary" @onclick="NavigateToNew">
        <i class="bi bi-plus-circle me-1"></i> New Appointment
    </button>
</div>

<div class="d-flex justify-content-between align-items-center mb-3">
    <button class="btn btn-outline-secondary" @onclick="PreviousWeek">&laquo; Previous Week</button>
    <div class="text-center">
        <strong>@weekStart.ToString("MMM d") &ndash; @weekEnd.ToString("MMM d, yyyy")</strong>
        <br />
        <button class="btn btn-sm btn-link" @onclick="CurrentWeek">Current Week</button>
    </div>
    <button class="btn btn-outline-secondary" @onclick="NextWeek">Next Week &raquo;</button>
</div>

@if (isLoading)
{
    <div class="text-center my-5">
        <div class="spinner-border text-primary" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else
{
    <div class="table-responsive">
        <table class="table table-bordered table-sm align-middle">
            <thead class="table-light">
                <tr>
                    <th style="min-width:80px;">Time</th>
                    @for (int d = 0; d < 7; d++)
                    {
                        var day = weekStart.AddDays(d);
                        var slotCount = availableSlotCounts.GetValueOrDefault(day.Date);
                        <th class="text-center" style="min-width:160px;">
                            <div>@day.ToString("ddd")</div>
                            <div class="small text-muted">@day.ToString("MMM d")</div>
                            <span class="badge bg-info">@slotCount available</span>
                        </th>
                    }
                </tr>
            </thead>
            <tbody>
                @foreach (var time in timeSlots)
                {
                    <tr>
                        <td class="text-nowrap fw-semibold small">@time.ToString("h:mm tt")</td>
                        @for (int d = 0; d < 7; d++)
                        {
                            var slotStart = weekStart.AddDays(d).Add(time);
                            var slotEnd = slotStart.AddMinutes(30);
                            var overlapping = GetOverlappingAppointments(slotStart, slotEnd);
                            <td class="p-1" style="vertical-align:top;">
                                @foreach (var appt in overlapping)
                                {
                                    <div class="card mb-1 border-0 shadow-sm appointment-card @GetCardClass(appt.Status)"
                                         style="cursor:pointer; font-size:.8rem;"
                                         @onclick="() => NavigateToAppointment(appt.Id)">
                                        <div class="card-body p-1">
                                            <div class="fw-bold">@appt.Pet?.Name</div>
                                            <div class="text-muted">@appt.Pet?.Owner?.FullName</div>
                                            <div class="text-truncate">@appt.Reason</div>
                                            <span class="badge @GetBadgeClass(appt.Status)">@appt.Status</span>
                                        </div>
                                    </div>
                                }
                            </td>
                        }
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    private DateTime weekStart;
    private DateTime weekEnd;
    private bool isLoading = true;
    private List<Appointment> appointments = [];
    private Dictionary<DateTime, int> availableSlotCounts = new();

    private static readonly List<TimeSpan> timeSlots = Enumerable.Range(0, 20)
        .Select(i => TimeSpan.FromHours(8) + TimeSpan.FromMinutes(30 * i))
        .ToList(); // 8:00 AM to 5:30 PM (last slot starts at 5:30, ends at 6:00)

    protected override async Task OnInitializedAsync()
    {
        SetWeek(DateTime.Today);
        await LoadDataAsync();
    }

    private void SetWeek(DateTime date)
    {
        int diff = (7 + (date.DayOfWeek - DayOfWeek.Monday)) % 7;
        weekStart = date.AddDays(-diff).Date;
        weekEnd = weekStart.AddDays(6);
    }

    private async Task LoadDataAsync()
    {
        isLoading = true;
        try
        {
            appointments = await ClinicService.GetAppointmentsAsync(weekStart, weekEnd.AddDays(1));

            availableSlotCounts.Clear();
            var tasks = Enumerable.Range(0, 7).Select(async d =>
            {
                var day = weekStart.AddDays(d);
                var slots = await ClinicService.GetAvailableSlotsAsync(day, 30);
                return (day.Date, slots.Count);
            });

            foreach (var result in await Task.WhenAll(tasks))
            {
                availableSlotCounts[result.Date] = result.Count;
            }
        }
        finally
        {
            isLoading = false;
        }
    }

    private List<Appointment> GetOverlappingAppointments(DateTime slotStart, DateTime slotEnd)
    {
        return appointments.Where(a =>
            a.StartTime < slotEnd && a.EndTime > slotStart
        ).ToList();
    }

    private async Task PreviousWeek()
    {
        SetWeek(weekStart.AddDays(-7));
        await LoadDataAsync();
    }

    private async Task NextWeek()
    {
        SetWeek(weekStart.AddDays(7));
        await LoadDataAsync();
    }

    private async Task CurrentWeek()
    {
        SetWeek(DateTime.Today);
        await LoadDataAsync();
    }

    private void NavigateToNew() => Navigation.NavigateTo("/appointments/new");

    private void NavigateToAppointment(int id) => Navigation.NavigateTo($"/appointments/{id}");

    private static string GetBadgeClass(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Scheduled => "bg-success",
        AppointmentStatus.Completed => "bg-secondary",
        AppointmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };

    private static string GetCardClass(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Scheduled => "border-start border-success border-3",
        AppointmentStatus.Completed => "border-start border-secondary border-3",
        AppointmentStatus.Cancelled => "border-start border-danger border-3",
        _ => ""
    };
}

@page "/appointments/new"
@page "/appointments/{Id:int}"
@rendermode InteractiveServer
@attribute [Authorize]
