            </div>
        </div>
    }

    <EditForm Model="@appointment" OnValidSubmit="HandleSave" FormName="appointmentForm">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="row">
            <div class="col-md-6">
                @* --- Pet selection (new only) --- *@
                @if (IsNew)
                {
                    <div class="mb-3">
                        <label class="form-label fw-semibold">Pet <span class="text-danger">*</span></label>
