                    </div>
                }

                @* --- Date selection --- *@
                <div class="mb-3">
                    <label class="form-label fw-semibold">Date <span class="text-danger">*</span></label>
                    <input type="date" class="form-control" value="@selectedDate?.ToString("yyyy-MM-dd")"
                           @onchange="OnDateChanged" />
                </div>

                @* --- Duration --- *@
                <div class="mb-3">
                    <label class="form-label fw-semibold">Duration (minutes)</label>
                    <select class="form-select" value="@appointment!.DurationMinutes"
                            @onchange="OnDurationChanged">
                        <option value="15">15 minutes</option>
                        <option value="30">30 minutes</option>
                        <option value="45">45 minutes</option>
                        <option value="60">60 minutes</option>
                    </select>
                </div>

                @* --- Available time slots --- *@
                @if (selectedDate.HasValue)
                {
                    <div class="mb-3">
                        <label class="form-label fw-semibold">Available Time Slots</label>
                        @if (isLoadingSlots)
                        {
                            <div class="text-muted">
                                <span class="spinner-border spinner-border-sm me-1"></span> Loading slots...
                            </div>
                        }
                        else if (availableSlots.Count == 0)
                        {
                            <div class="text-muted">No available slots for this date and duration.</div>
                        }
                        else
                        {
                            <div class="d-flex flex-wrap gap-2">
                                @foreach (var slot in availableSlots)
                                {
                                    var isSelected = appointment.StartTime == slot.StartTime;
                                    <button type="button"
                                            class="btn btn-sm @(isSelected ? "btn-primary" : "btn-outline-primary")"
                                            @onclick="() => SelectSlot(slot)">
                                        @slot.StartTime.ToString("h:mm tt")
                                    </button>
                                }
                            </div>
                        }
                    </div>
                }

                @* --- Existing appointment: manual time edit --- *@
                @if (!IsNew)
                {
                    <div class="mb-3">
                        <label class="form-label fw-semibold">Start Time</label>
                        <div class="d-flex gap-2">
                            <input type="date" class="form-control"
                                   value="@appointment.StartTime.ToString("yyyy-MM-dd")"
                                   @onchange="OnStartDateChanged" />
                            <input type="time" class="form-control"
                                   value="@appointment.StartTime.ToString("HH:mm")"
                                   @onchange="OnStartTimeChanged" />
                        </div>
                    </div>
                }
            </div>

            <div class="col-md-6">
                <div class="mb-3">
                    <label class="form-label fw-semibold">Reason <span class="text-danger">*</span></label>
                    <InputText class="form-control" @bind-Value="appointment!.Reason" />
                    <ValidationMessage For="() => appointment.Reason" />
                </div>

                <div class="mb-3">
                    <label class="form-label fw-semibold">Veterinarian <span class="text-danger">*</span></label>
                    <InputText class="form-control" @bind-Value="appointment!.VetName" />
                    <ValidationMessage For="() => appointment.VetName" />
                </div>

                <div class="mb-3">
                    <label class="form-label fw-semibold">Notes</label>
                    <InputTextArea class="form-control" @bind-Value="appointment!.Notes" rows="3" />
                </div>

                @if (!IsNew)
                {
                    <div class="mb-3">
                        <label class="form-label fw-semibold">Status</label>
                        <InputSelect class="form-select" @bind-Value="appointment!.Status">
                            @foreach (var s in Enum.GetValues<AppointmentStatus>())
                            {
                                <option value="@s">@s</option>
                            }
                        </InputSelect>
                    </div>
                }
            </div>
        </div>

        @if (hasConflict)
        {
            <div class="alert alert-warning">
                <strong>Scheduling conflict detected!</strong> Another appointment overlaps with the selected time slot.
            </div>
        }

        <div class="d-flex gap-2 mt-3">
            <button type="submit" class="btn btn-success" disabled="@isSaving">
                @if (isSaving)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                @(IsNew ? "Create Appointment" : "Save Changes")
            </button>

            @if (!IsNew && appointment!.Status == AppointmentStatus.Scheduled)
            {
                <button type="button" class="btn btn-danger" @onclick="HandleCancel" disabled="@isSaving">
                    Cancel Appointment
                </button>
            }
        </div>
    </EditForm>

    @* --- Treatment notes for existing appointments --- *@
    @if (!IsNew && appointment?.TreatmentNotes?.Count > 0)
    {
        <hr class="my-4" />
        <h4>Treatment Notes</h4>
        <div class="list-group">
            @foreach (var note in appointment.TreatmentNotes.OrderByDescending(n => n.Date))
            {
                <div class="list-group-item">
                    <div class="d-flex justify-content-between">
                        <h6 class="mb-1">@note.Title</h6>
                        <small class="text-muted">@note.Date.ToString("MMM d, yyyy h:mm tt")</small>
                    </div>
                    @if (!string.IsNullOrEmpty(note.Diagnosis))
                    {
                        <p class="mb-1"><strong>Diagnosis:</strong> @note.Diagnosis</p>
                    }
                    @if (!string.IsNullOrEmpty(note.Medication))
                    {
                        <p class="mb-1"><strong>Medication:</strong> @note.Medication</p>
                    }
                    @if (!string.IsNullOrEmpty(note.Description))
                    {
                        <p class="mb-0 text-muted">@note.Description</p>
                    }
                    <small class="text-muted">By @note.StaffName</small>
                </div>
            }
        </div>
    }

    @* --- Reschedule section for existing appointments --- *@
    @if (!IsNew && appointment?.Status == AppointmentStatus.Scheduled)
    {
        <hr class="my-4" />
        <h4>Reschedule</h4>
        <p class="text-muted">Pick a new date and click an available slot to reschedule this appointment.</p>
        <div class="row">
            <div class="col-md-4">
                <input type="date" class="form-control" value="@rescheduleDate?.ToString("yyyy-MM-dd")"
                       @onchange="OnRescheduleDateChanged" />
            </div>
        </div>
        @if (rescheduleDate.HasValue)
        {
            <div class="mt-3">
                @if (isLoadingRescheduleSlots)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span> Loading slots...
                }
                else if (rescheduleSlots.Count == 0)
                {
                    <span class="text-muted">No available slots for this date.</span>
                }
                else
                {
                    <div class="d-flex flex-wrap gap-2">
                        @foreach (var slot in rescheduleSlots)
                        {
                            <button type="button" class="btn btn-sm btn-outline-info"
                                    @onclick="() => ApplyReschedule(slot)">
                                @slot.StartTime.ToString("h:mm tt")
                            </button>
                        }
                    </div>
                }
            </div>
        }
    }
}

@code {
    [Parameter] public int Id { get; set; }

    private bool IsNew => Id == 0;
    private Appointment? appointment;
    private List<Pet> pets = [];
    private List<Appointment> availableSlots = [];
    private List<Appointment> rescheduleSlots = [];
    private DateTime? selectedDate;
    private DateTime? rescheduleDate;

    private bool isLoading = true;
    private bool isLoadingSlots;
    private bool isLoadingRescheduleSlots;
    private bool isSaving;
    private bool hasConflict;

    private string? successMessage;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        if (IsNew)
        {
            appointment = new Appointment
            {
                StartTime = DateTime.Today.AddHours(8),
                DurationMinutes = 30,
                Status = AppointmentStatus.Scheduled
            };
            pets = await ClinicService.GetPetsAsync();
        }
        else
        {
            appointment = await ClinicService.GetAppointmentAsync(Id);
            if (appointment != null)
            {
                selectedDate = appointment.StartTime.Date;
            }
        }
        isLoading = false;
    }

    private async Task OnDateChanged(ChangeEventArgs e)
    {
        if (DateTime.TryParse(e.Value?.ToString(), out var date))
        {
            selectedDate = date;
            await LoadAvailableSlots();
        }
    }

    private async Task OnDurationChanged(ChangeEventArgs e)
    {
        if (int.TryParse(e.Value?.ToString(), out var duration))
        {
            appointment!.DurationMinutes = duration;
            if (selectedDate.HasValue)
            {
                await LoadAvailableSlots();
            }
        }
    }

    private async Task LoadAvailableSlots()
    {
        isLoadingSlots = true;
        hasConflict = false;
        try
        {
            availableSlots = await ClinicService.GetAvailableSlotsAsync(
                selectedDate!.Value, appointment!.DurationMinutes);
        }
        finally
        {
            isLoadingSlots = false;
        }
    }

    private void SelectSlot(Appointment slot)
    {
        appointment!.StartTime = slot.StartTime;
        hasConflict = false;
    }

    private void OnStartDateChanged(ChangeEventArgs e)
    {
        if (DateTime.TryParse(e.Value?.ToString(), out var date))
        {
            var time = appointment!.StartTime.TimeOfDay;
            appointment.StartTime = date.Date + time;
            selectedDate = date.Date;
        }
    }

    private void OnStartTimeChanged(ChangeEventArgs e)
    {
        if (TimeSpan.TryParse(e.Value?.ToString(), out var time))
        {
            appointment!.StartTime = appointment.StartTime.Date + time;
        }
    }

    private async Task HandleSave()
    {
        ClearMessages();
        if (appointment!.PetId == 0)
        {
            errorMessage = "Please select a pet.";
            return;
        }

        isSaving = true;
        try
        {
            bool conflict = await ClinicService.HasConflictAsync(
                appointment.StartTime,
                appointment.DurationMinutes,
                IsNew ? null : appointment.Id);

            if (conflict)
            {
                hasConflict = true;
                errorMessage = "Cannot save: another appointment conflicts with this time slot.";
                return;
            }

            hasConflict = false;
            await ClinicService.SaveAppointmentAsync(appointment);
            Navigation.NavigateTo("/appointments");
        }
        catch (Exception ex)
        {
            errorMessage = $"Error saving appointment: {ex.Message}";
        }
        finally
        {
            isSaving = false;
        }
    }

    private async Task HandleCancel()
    {
        ClearMessages();
        isSaving = true;
        try
        {
            await ClinicService.CancelAppointmentAsync(appointment!.Id);
            appointment.Status = AppointmentStatus.Cancelled;
            successMessage = "Appointment cancelled successfully.";
        }
        catch (Exception ex)
        {
            errorMessage = $"Error cancelling appointment: {ex.Message}";
        }
        finally
        {
            isSaving = false;
        }
    }

    private async Task OnRescheduleDateChanged(ChangeEventArgs e)
    {
        if (DateTime.TryParse(e.Value?.ToString(), out var date))
        {
            rescheduleDate = date;
            isLoadingRescheduleSlots = true;
            try
            {
                rescheduleSlots = await ClinicService.GetAvailableSlotsAsync(
                    date, appointment!.DurationMinutes);
            }
            finally
            {
                isLoadingRescheduleSlots = false;
            }
        }
    }

    private async Task ApplyReschedule(Appointment slot)
    {
        appointment!.StartTime = slot.StartTime;
        selectedDate = slot.StartTime.Date;
        ClearMessages();

        isSaving = true;
        try
        {
            bool conflict = await ClinicService.HasConflictAsync(
                appointment.StartTime,
                appointment.DurationMinutes,
                appointment.Id);

            if (conflict)
            {
                hasConflict = true;
                errorMessage = "Conflict detected for the selected reschedule slot.";
                return;
            }

            hasConflict = false;
            await ClinicService.SaveAppointmentAsync(appointment);
            successMessage = $"Appointment rescheduled to {appointment.StartTime:MMM d, yyyy h:mm tt}.";
            rescheduleDate = null;
            rescheduleSlots.Clear();
        }
        catch (Exception ex)
        {
            errorMessage = $"Error rescheduling: {ex.Message}";
        }
        finally
        {
            isSaving = false;
        }
    }

    private void ClearMessages()
    {
        successMessage = null;
        errorMessage = null;
    }

    private static string GetBadgeClass(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Scheduled => "bg-success",
        AppointmentStatus.Completed => "bg-secondary",
        AppointmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}

@page "/appointments"
@rendermode InteractiveServer
@attribute [Authorize]
@using VetClinic.Data.Models
@using VetClinic.Services
@using Microsoft.AspNetCore.Authorization
@inject ClinicService ClinicService
@inject NavigationManager Navigation

<PageTitle>Appointment Schedule</PageTitle>

<div class="d-flex justify-content-between align-items-center mb-3">
    <h2 class="mb-0">Appointment Schedule</h2>
    <button class="btn btn-primary" @onclick="NavigateToNew">
        <i class="bi bi-plus-circle me-1"></i> New Appointment
    </button>
</div>

<div class="d-flex justify-content-between align-items-center mb-3">
    <button class="btn btn-outline-secondary" @onclick="PreviousWeek">&laquo; Previous Week</button>
    <div class="text-center">
        <strong>@weekStart.ToString("MMM d") &ndash; @weekEnd.ToString("MMM d, yyyy")</strong>
        <br />
        <button class="btn btn-sm btn-link" @onclick="CurrentWeek">Current Week</button>
    </div>
    <button class="btn btn-outline-secondary" @onclick="NextWeek">Next Week &raquo;</button>
</div>

@if (isLoading)
{
    <div class="text-center my-5">
        <div class="spinner-border text-primary" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else
{
    <div class="table-responsive">
        <table class="table table-bordered table-sm align-middle">
            <thead class="table-light">
                <tr>
                    <th style="min-width:80px;">Time</th>
                    @for (int d = 0; d < 7; d++)
                    {
                        var day = weekStart.AddDays(d);
                        var slotCount = availableSlotCounts.GetValueOrDefault(day.Date);
                        <th class="text-center" style="min-width:160px;">
                            <div>@day.ToString("ddd")</div>
                            <div class="small text-muted">@day.ToString("MMM d")</div>
                            <span class="badge bg-info">@slotCount available</span>
                        </th>
                    }
                </tr>
            </thead>
            <tbody>
                @foreach (var time in timeSlots)
                {
                    <tr>
                        <td class="text-nowrap fw-semibold small">@time.ToString("h:mm tt")</td>
                        @for (int d = 0; d < 7; d++)
                        {
                            var slotStart = weekStart.AddDays(d).Add(time);
                            var slotEnd = slotStart.AddMinutes(30);
                            var overlapping = GetOverlappingAppointments(slotStart, slotEnd);
                            <td class="p-1" style="vertical-align:top;">
                                @foreach (var appt in overlapping)
                                {
                                    <div class="card mb-1 border-0 shadow-sm appointment-card @GetCardClass(appt.Status)"
                                         style="cursor:pointer; font-size:.8rem;"
                                         @onclick="() => NavigateToAppointment(appt.Id)">
                                        <div class="card-body p-1">
                                            <div class="fw-bold">@appt.Pet?.Name</div>
                                            <div class="text-muted">@appt.Pet?.Owner?.FullName</div>
                                            <div class="text-truncate">@appt.Reason</div>
                                            <span class="badge @GetBadgeClass(appt.Status)">@appt.Status</span>
                                        </div>
                                    </div>
                                }
                            </td>
                        }
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    private DateTime weekStart;
    private DateTime weekEnd;
    private bool isLoading = true;
    private List<Appointment> appointments = [];
    private Dictionary<DateTime, int> availableSlotCounts = new();

    private static readonly List<TimeSpan> timeSlots = Enumerable.Range(0, 20)
        .Select(i => TimeSpan.FromHours(8) + TimeSpan.FromMinutes(30 * i))
        .ToList(); // 8:00 AM to 5:30 PM (last slot starts at 5:30, ends at 6:00)

    protected override async Task OnInitializedAsync()
    {
        SetWeek(DateTime.Today);
        await LoadDataAsync();
    }

    private void SetWeek(DateTime date)
    {
        int diff = (7 + (date.DayOfWeek - DayOfWeek.Monday)) % 7;
        weekStart = date.AddDays(-diff).Date;
        weekEnd = weekStart.AddDays(6);
    }

    private async Task LoadDataAsync()
    {
        isLoading = true;
        try
        {
            appointments = await ClinicService.GetAppointmentsAsync(weekStart, weekEnd.AddDays(1));

            availableSlotCounts.Clear();
            var tasks = Enumerable.Range(0, 7).Select(async d =>
            {
                var day = weekStart.AddDays(d);
                var slots = await ClinicService.GetAvailableSlotsAsync(day, 30);
                return (day.Date, slots.Count);
            });

            foreach (var result in await Task.WhenAll(tasks))
            {
                availableSlotCounts[result.Date] = result.Count;
            }
        }
        finally
        {
            isLoading = false;
        }
    }

    private List<Appointment> GetOverlappingAppointments(DateTime slotStart, DateTime slotEnd)
    {
        return appointments.Where(a =>
            a.StartTime < slotEnd && a.EndTime > slotStart
        ).ToList();
    }

    private async Task PreviousWeek()
    {
        SetWeek(weekStart.AddDays(-7));
        await LoadDataAsync();
    }

    private async Task NextWeek()
    {
        SetWeek(weekStart.AddDays(7));
        await LoadDataAsync();
    }

    private async Task CurrentWeek()
    {
        SetWeek(DateTime.Today);
        await LoadDataAsync();
    }

    private void NavigateToNew() => Navigation.NavigateTo("/appointments/new");

    private void NavigateToAppointment(int id) => Navigation.NavigateTo($"/appointments/{id}");

    private static string GetBadgeClass(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Scheduled => "bg-success",
        AppointmentStatus.Completed => "bg-secondary",
        AppointmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };

    private static string GetCardClass(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Scheduled => "border-start border-success border-3",
        AppointmentStatus.Completed => "border-start border-secondary border-3",
        AppointmentStatus.Cancelled => "border-start border-danger border-3",
        _ => ""
    };
}

